/**
 * Stripe V2 capabilities mapped to convenience booleans.

Stripe V2 does NOT expose top-level `charges_enabled` /
`payouts_enabled` booleans the way V1 did — those values must
be derived from `account.configuration.recipient.capabilities.*`.
The mapping below is OUR normalization for admin UI convenience.
The full V2 capabilities object is also returned in `capabilities`
for inspection.

Mapping (V2 capability → boolean):
  - `chargesEnabled`      ← (no direct V2 equivalent — Connect
      accounts in V2 are recipient-only; this stays `false` for
      transfer-only accounts and is reserved for future use if
      we add merchant capabilities)
  - `payoutsEnabled`      ← `configuration.recipient.capabilities
      .stripe_balance.stripe_transfers.status === "active"`
      i.e. the supplier can receive transfers from our platform
      balance into their Stripe balance and have them paid out.
  - `detailsSubmitted`    ← `configuration.recipient.requirements
      .currently_due` is empty (i.e. Stripe has no outstanding
      asks blocking onboarding). `eventually_due` items do NOT
      block — they are future requirements (e.g. when the supplier
      crosses a transaction-volume threshold) and are surfaced
      separately to admins via the raw `capabilities` blob.
      This formula is the canonical definition for both this
      field and any server-side gating logic.

 */
export interface SupplierOnboardingStatusResponse {
  supplierId: string;
  stripeAccountId?: string | null;
  stripeOnboardingStatus: SupplierOnboardingStatus;
  /** Reserved — currently always false for V2 recipient-only accounts */
  chargesEnabled: boolean;
  /** Derived from V2 stripe_transfers capability status === "active" */
  payoutsEnabled: boolean;
  /** True when V2 requirements.currently_due is empty */
  detailsSubmitted: boolean;
  /** V2 configuration.recipient.requirements.currently_due */
  requirementsCurrentlyDue: string[];
  /** V2 configuration.recipient.requirements.past_due */
  requirementsPastDue: string[];
  /** Live snapshot of `account.configuration.recipient.capabilities`
from V2 — used for inspection/forensics; clients should prefer
the normalized booleans above for routine display.
 */
  capabilities?: unknown | null;
  /** When the live data was fetched (cache age = now - fetchedAt) */
  fetchedAt: string;
  /** True if returned from in-memory cache (≤60s old) */
  cached: boolean;
}

